#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Node {
public:
    int val;
    Node* next;
    Node* random;

    Node(int _val) {
        val = _val;
        next = NULL;
        random = NULL;
    }
};

class Solution {
public:
    Node* copyRandomList(Node* head) {
        if (!head) return NULL;

        unordered_map<Node*, Node*> old_to_new;
        Node* curr = head;
        while (curr) {
            old_to_new[curr] = new Node(curr->val);
            curr = curr->next;
        }

        curr = head;
        while (curr) {
            if (curr->next) {
                old_to_new[curr]->next = old_to_new[curr->next];
            }
            if (curr->random) {
                old_to_new[curr]->random = old_to_new[curr->random];
            }
            curr = curr->next;
        }

        return old_to_new[head];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<pair<int, int>> nodes(n);
    for (int i = 0; i < n; i++) {
        cin >> nodes[i].first >> nodes[i].second;
    }

    Node* head = new Node(nodes[0].first);
    Node* curr = head;
    vector<Node*> node_list = {head};
    for (int i = 1; i < n; i++) {
        curr->next = new Node(nodes[i].first);
        curr = curr->next;
        node_list.push_back(curr);
    }

    for (int i = 0; i < n; i++) {
        if (nodes[i].second != -1) {
            node_list[i]->random = node_list[nodes[i].second];
        }
    }

    Solution sol;
    Node* new_head = sol.copyRandomList(head);

    vector<Node*> new_node_list;
    while (new_head) {
        new_node_list.push_back(new_head);
        new_head = new_head->next;
    }

    cout << n << endl;
    for (int i = 0; i < n; i++) {
        int random_index = -1;
        if (new_node_list[i]->random) {
            random_index = distance(new_node_list.begin(), find(new_node_list.begin(), new_node_list.end(), new_node_list[i]->random));
        }
        cout << new_node_list[i]->val << ' ' << random_index << endl;
    }

    return 0;
}
